 32→pub struct TextInput {
 33→    pub focus_handle: FocusHandle,
 34→    pub content: SharedString,
 35→    pub placeholder: SharedString,
 36→    pub selected_range: Range<usize>,
 37→    pub selection_reversed: bool,
